// 方向を表す
int dx[] = {-1, 0, 1, 0};
int dy[] = {0, 1, 0, -1};
std::random_device rd;

constexpr int N = 9;

// 操作
struct Act {
	int type, x, y;
};

class Game {
  public:
	std::vector<std::vector<bool>> C;
	std::vector<std::vector<bool>> wall_hrz, wall_vert;
	std::array<int, 2> X, Y, wall_used, score;
	bool is_finished = false;

	int MAX_WALL = 10;
	int turn = 0;
	std::vector<Act> acts;

	bool isConnected() {
		UnionFind uf(81);
		rep(i, N) rep(j, N) {
			if (i < 8 && !wall_hrz[i][j]) uf.unite(i * N + j, (i + 1) * N + j);
			if (j < 8 && !wall_vert[i][j]) uf.unite(i * N + j, i * N + j + 1);
		}
		return uf.get_size(uf.find(0)) == N * N;
	}

	bool isOK(Act act, int fromX = -1, int fromY = -1) {
		if (fromX == -1) fromX = X[turn], fromY = Y[turn];
		if (act.type == 0) {
			if (act.x == 0)
				return fromX && !wall_hrz[fromX - 1][fromY];
			else if (act.x == 1)
				return fromY != N - 1 && !wall_vert[fromX][fromY];
			else if (act.x == 2)
				return fromX != N - 1 && !wall_hrz[fromX][fromY];
			else if (act.x == 3)
				return fromY && !wall_vert[fromX][fromY - 1];
			else
				return false;
		} else if (act.type == 1) {
			if (act.x < 0 || N - 1 <= act.x || act.y < 0 || N - 1 <= act.y)
				return false;
			if (wall_used[turn] == MAX_WALL) return false;
			if (wall_hrz[act.x][act.y] || wall_hrz[act.x][act.y + 1])
				return false;
			wall_hrz[act.x][act.y] = wall_hrz[act.x][act.y + 1] = true;
			bool res = isConnected();
			wall_hrz[act.x][act.y] = wall_hrz[act.x][act.y + 1] = false;
			return res;
		} else if (act.type == 2) {
			if (act.x < 0 || N - 1 <= act.x || act.y < 0 || N - 1 <= act.y)
				return false;
			if (wall_used[turn] == MAX_WALL) return false;
			if (wall_vert[act.x][act.y] || wall_vert[act.x + 1][act.y])
				return false;
			wall_vert[act.x][act.y] = wall_vert[act.x + 1][act.y] = true;
			bool res = isConnected();
			wall_vert[act.x][act.y] = wall_vert[act.x + 1][act.y] = false;
			return res;
		} else
			return false;
	}

	std::vector<Act> candidateActs() {
		std::vector<Act> res;
		rep(i, 4) {
			if (isOK(Act{0, i, 0})) res.push_back(Act{0, i, 0});
		}
		rep(i, 9) rep(j, 9) {
			if (isOK(Act{1, i, j})) res.push_back(Act{1, i, j});
			if (isOK(Act{2, i, j})) res.push_back(Act{2, i, j});
		}
		return res;
	}

	std::pair<std::vector<std::vector<int>>, std::vector<std::vector<int>>> bfs(
		int t) {
		std::queue<IP> que;
		que.push({X[t], Y[t]});
		auto dist = make_vec<int>(N, N);
		auto first_move = make_vec<int>(N, N);
		rep(i, N) rep(j, N) dist[i][j] = INF;
		dist[X[t]][Y[t]] = 0;
		while (!que.empty()) {
			const IP p = que.front();
			que.pop();
			rep(i, 4) {
				const int nx = p.first + dx[i], ny = p.second + dy[i];
				if (isOK({0, i, 0}, p.first, p.second) && dist[nx][ny] == INF) {
					if (!dist[p.first][p.second])
						first_move[nx][ny] = i;
					else
						first_move[nx][ny] = first_move[p.first][p.second];
					dist[nx][ny] = dist[p.first][p.second] + 1;
					que.push({nx, ny});
				}
			}
		}
		return {dist, first_move};
	}

	std::pair<int, Act> bfs_best(int t) {
		int min_sum = INF;
		Act cand;
		rep(i, 4) {
			if (isOK({0, i, 0}, X[t], Y[t])) {
				X[t] += dx[i], Y[t] += dy[i];
				int sum = 0;
				if (C[X[t]][Y[t]]) sum -= 60;
				auto dist = bfs(t).first;
				rep(k, N) rep(l, N) if (C[k][l]) sum += dist[k][l];
				if (chmin(min_sum, sum)) cand = {0, i, 0};
				X[t] -= dx[i], Y[t] -= dy[i];
			}
		}
		return {min_sum, cand};
	}

	std::pair<int, Act> jam_best(int t) {
		int max_sum = -INF;
		Act cand;
		rep(i, N) rep(j, N) {
			if (isOK(Act{1, i, j})) {
				wall_hrz[i][j] = wall_hrz[i][j + 1] = true;
				int cnt = 0;
				auto dist = bfs(t ^ 1).first;
				rep(k, N) rep(l, N) if (C[k][l]) cnt += dist[k][l];
				dist = bfs(t).first;
				rep(k, N) rep(l, N) if (C[k][l]) cnt -= dist[k][l];
				if (chmax(max_sum, cnt)) cand = {1, i, j};
				wall_hrz[i][j] = wall_hrz[i][j + 1] = false;
			}
		}
		rep(i, N) rep(j, N) {
			if (isOK(Act{2, i, j})) {
				wall_vert[i][j] = wall_vert[i + 1][j] = true;
				int cnt = 0;
				auto dist = bfs(t ^ 1).first;
				rep(k, N) rep(l, N) if (C[k][l]) cnt += dist[k][l];
				dist = bfs(t).first;
				rep(k, N) rep(l, N) if (C[k][l]) cnt -= dist[k][l];
				if (chmax(max_sum, cnt)) cand = {2, i, j};
				wall_vert[i][j] = wall_vert[i + 1][j] = false;
			}
		}
		return {max_sum, cand};
	}

	// 操作を実行する
	bool applyAct(Act act, bool check = true) {
		if (check && !isOK(act)) return false;
		if (act.type == 0) {  // 隣接マスへ移動
			X[turn] += dx[act.x];
			Y[turn] += dy[act.x];
			if (C[X[turn]][Y[turn]]) {
				score[turn]++;
				C[X[turn]][Y[turn]] = false;
			}
		} else if (act.type == 1) {	 // 水平方向の壁
			wall_hrz[act.x][act.y] = wall_hrz[act.x][act.y + 1] = true;
			wall_used[turn]++;
		} else {  // 垂直方向の壁
			wall_vert[act.x][act.y] = wall_vert[act.x + 1][act.y] = true;
			wall_used[turn]++;
		}
		// ゲームが終了しているかの判定
		bool flag = false;
		rep(i, 9) rep(j, 9) {
			if (C[i][j]) flag = true;
		}
		if (!flag) is_finished = true;
		acts.push_back(act);

		// 交代
		turn ^= 1;
		return true;
	}

	// スコアや盤面を出力する（デバッグ用）
	void printBoard() {
		std::cerr << "Score: " << score[0] << " " << score[1] << "\n"
				  << "Wall counter: " << wall_used[0] << " " << wall_used[1]
				  << std::endl
				  << std::endl;
		rep(i, 9) {
			rep(j, 9) {
				if (i == X[0] && j == Y[0] && i == X[1] && j == Y[1])
					std::cerr << " AB";
				else if (i == X[0] && j == Y[0])
					std::cerr << " A ";
				else if (i == X[1] && j == Y[1])
					std::cerr << " B ";
				else {
					if (C[i][j])
						std::cerr << " # ";
					else
						std::cerr << " . ";
				}
				if (j < N - 1) std::cerr << (wall_vert[i][j] ? " | " : "   ");
			}
			std::cerr << std::endl;
			if (i != N - 1) {
				rep(j, N) {
					if (j) std::cerr << "   ";
					std::cerr << (wall_hrz[i][j] ? "---" : "   ");
				}
			}
			std::cerr << std::endl;
		}
		std::cerr << std::endl;
	}
	Game()
		: C(9, std::vector<bool>(9)),
		  wall_hrz(9, std::vector<bool>(9)),
		  wall_vert(9, std::vector<bool>(9)) {
		wall_used[0] = wall_used[1] = 0;
		score[0] = score[1] = 0;
		X[0] = 8, X[1] = 0, Y[0] = Y[1] = 4;
	}
};

double tim_sum;

Act choose(Game& game) {
	std::chrono::system_clock::time_point clk =
		std::chrono::system_clock::now();

	Act best_act;
	auto act1 = game.jam_best(game.turn);
	auto act2 = game.bfs_best(game.turn);
	if (act1.first > 10 && game.wall_used[game.turn] != game.MAX_WALL)
		best_act = act1.second;
	else
		best_act = act2.second;

	tim_sum += static_cast<double>(
		std::chrono::duration_cast<std::chrono::microseconds>(
			std::chrono::system_clock::now() - clk)
			.count() /
		1000000.0);

	return best_act;
}
int main() {
	std::string s;
	std::cin >> s;
	Game game;
	rep(i, N) {
		rep(j, N) {
			char c;
			std::cin >> c;
			if (c == '#')
				game.C[i][j] = true;
			else
				game.C[i][j] = false;
		}
	}
	int turn = 0, myturn = (s == "First" ? 0 : 1);
	while (1) {
		if (turn == myturn) {
			Act act = choose(game);
			assert(game.applyAct(act));
			if (!act.type) {
				std::cout << act.type << " " << act.x << std::endl;
			} else {
				std::cout << act.type << " " << act.x << " " << act.y
						  << std::endl;
			}
		} else {
			int t;
			std::cin >> t;
			if (!t) {
				int x;
				std::cin >> x;
				assert(game.applyAct(Act{0, x, 0}));
			} else if (t <= 2) {
				int x, y;
				std::cin >> x >> y;
				game.applyAct(Act{t, x, y});
			} else {
				return 0;
			}
		}
		game.printBoard();
		turn ^= 1;
	}
}
